import signal
import pytest
from source import find_first_in_sorted


def _timeout_handler(signum, frame):
    raise TimeoutError("infinite loop detected")


def test_find_first_occurrence_with_duplicates_terminates_and_returns_correct_index():
    signal.signal(signal.SIGALRM, _timeout_handler)
    signal.alarm(2)
    try:
        result = find_first_in_sorted([3, 4, 5, 5, 5, 6], 5)
    except TimeoutError:
        pytest.fail(
            "find_first_in_sorted([3, 4, 5, 5, 5, 6], 5) looped forever — "
            "lo==hi==mid with x<=arr[mid] keeps resetting hi=mid without advancing lo"
        )
    finally:
        signal.alarm(0)

    assert result == 2, (
        f"Expected first occurrence of 5 at index 2, got {result}"
    )

import pytest
from source import find_first_in_sorted


def test_find_first_missing_target_larger_than_all_elements():
    # hi = len(arr) (off-by-one) causes arr[mid] IndexError when target > max element:
    # lo=4, hi=6, mid=5, arr[5]=6 < 7 → lo=6; lo=6, hi=6, mid=6, arr[6] → IndexError.
    # Fixed code (hi = len(arr) - 1) avoids out-of-bounds and returns -1.
    try:
        result = find_first_in_sorted([3, 4, 5, 5, 5, 6], 7)
    except Exception as e:
        pytest.fail(
            f"find_first_in_sorted raised {type(e).__name__} instead of returning -1: {e}"
        )
    assert result == -1, (
        f"Expected -1 when target (7) is larger than every element, got {result}"
    )
